private static final void encodeQuotedPrintable(int b, ByteArrayOutputStream buffer) {
    buffer.write(ESCAPE_CHAR);
    char hex1 = Character.toUpperCase(Character.forDigit((b >> 4) & 0xF, 16));
    char hex2 = Character.toUpperCase(Character.forDigit(b & 0xF, 16));
    buffer.write(hex1);
    buffer.write(hex2);
}

public static final byte[] encodeQuotedPrintable(BitSet printable, byte[] bytes) {
    if (bytes == null) {
        return null;
    }
    if (printable == null) {
        printable = PRINTABLE_CHARS;
    }
    ByteArrayOutputStream buffer = new ByteArrayOutputStream();
    int lineLength = 0;
    int length = bytes.length;

    for (int i = 0; i < length; i++) {
        byte c = bytes[i];
        int b = c;
        if (b < 0) {
            b = 256 + b;
        }

        // Check if this is trailing whitespace that needs encoding
        boolean encodeWhitespace = false;
        if (b == ' ' || b == '\t') {
            // Look ahead to see if this is trailing whitespace
            boolean isTrailing = true;
            for (int j = i + 1; j < length; j++) {
                byte next = bytes[j];
                int nb = next < 0 ? 256 + next : next;
                if (nb != ' ' && nb != '\t') {
                    isTrailing = false;
                    break;
                }
            }
            encodeWhitespace = isTrailing;
        }

        if (!encodeWhitespace && printable.get(b)) {
            // Safe to add literal character
            int bytesNeeded = 1;

            // Check if we need a soft line break
            if (lineLength + bytesNeeded > 76) {
                buffer.write(ESCAPE_CHAR);
                buffer.write('\r');
                buffer.write('\n');
                lineLength = 0;
            }

            buffer.write(b);
            lineLength++;
        } else {
            // Need to encode this byte
            int bytesNeeded = 3; // =XX

            // Check if we need a soft line break before encoding
            if (lineLength + bytesNeeded > 76) {
                buffer.write(ESCAPE_CHAR);
                buffer.write('\r');
                buffer.write('\n');
                lineLength = 0;
            }

            encodeQuotedPrintable(b, buffer);
            lineLength += 3;
        }
    }

    return buffer.toByteArray();
}

public static final byte[] decodeQuotedPrintable(byte[] bytes) throws DecoderException {
    if (bytes == null) {
        return null;
    }
    ByteArrayOutputStream buffer = new ByteArrayOutputStream();
    for (int i = 0; i < bytes.length; i++) {
        final int b = bytes[i];
        if (b == ESCAPE_CHAR) {
            try {
                // Check for soft line break (=\r\n or =\n)
                if (i + 1 < bytes.length) {
                    if (bytes[i + 1] == '\r') {
                        if (i + 2 < bytes.length && bytes[i + 2] == '\n') {
                            // Soft line break: =\r\n - skip all three
                            i += 2;
                            continue;
                        }
                    } else if (bytes[i + 1] == '\n') {
                        // Soft line break: =\n - skip both
                        i += 1;
                        continue;
                    }
                }

                // Otherwise decode hex digits
                int u = Utils.digit16(bytes[++i]);
                int l = Utils.digit16(bytes[++i]);
                buffer.write((char) ((u << 4) + l));
            } catch (ArrayIndexOutOfBoundsException e) {
                throw new DecoderException("Invalid quoted-printable encoding", e);
            }
        } else if (b == '\r' || b == '\n') {
            // Skip bare CR and LF
            continue;
        } else {
            // Append other octets
            buffer.write(b);
        }
    }
    return buffer.toByteArray();
}

