@Test
public void testLongLineWithoutSpecialChars() throws Exception {
    final QuotedPrintableCodec qpcodec = new QuotedPrintableCodec();

    // Test line longer than 76 characters with only printable chars
    String plain = "This is a very long line that contains only printable characters and should trigger a soft line break";
    String encoded = qpcodec.encode(plain);

    // Verify soft line break is inserted
    assertTrue(encoded.contains("=\r\n"));

    // Verify it decodes back correctly
    assertEquals(plain, qpcodec.decode(encoded));
}

@Test
public void testMultipleConsecutiveSpecialChars() throws Exception {
    final QuotedPrintableCodec qpcodec = new QuotedPrintableCodec();

    // Test multiple special characters in sequence
    String plain = "Test===data";
    String encoded = qpcodec.encode(plain);

    // All equals signs should be encoded
    assertTrue(encoded.contains("=3D"));

    // Verify round trip
    assertEquals(plain, qpcodec.decode(encoded));
}

@Test
public void testOnlyWhitespace() throws Exception {
    final QuotedPrintableCodec qpcodec = new QuotedPrintableCodec();

    // Test string with only trailing whitespace
    String plain = "   ";
    String encoded = qpcodec.encode(plain);

    // All whitespace should be encoded as it's trailing
    assertEquals("=20=20=20", encoded);

    // Verify decode
    assertEquals(plain, qpcodec.decode(encoded));
}
